    # =========================================================
    # GENERALIZATION & STATISTICS ENGINE
    # =========================================================

    def runAlgorithm(self, algorithm_function, algorithm_name):
        """Master function to run any algorithm, measure time, and calculate statistics."""
        buildings = self.Canvas.getBuildings()
        if not buildings:
            QtWidgets.QMessageBox.warning(self.centralwidget, "Pozor", "Nejprve načtěte data (*.shp).")
            return
            
        a = Algorithms()
        mbrs_res = []
        
        # Statistics variables
        valid_count = 0
        orig_perim_total = 0.0
        gen_perim_total = 0.0
        
        # Start highly precise timer
        start_time = time.perf_counter()
        
        for building in buildings:
            if len(building) >= 3:
                try:
                    # Execute the passed algorithm function dynamically
                    res = algorithm_function(a, building)
                    mbrs_res.append(res)
                    
                    # Accumulate perimeter stats
                    orig_perim_total += a.getPerimeter(building)
                    gen_perim_total += a.getPerimeter(res)
                    valid_count += 1
                    
                except Exception as e:
                    print(f"Skipping geometry in {algorithm_name}: {e}")
                    
        # Stop timer
        end_time = time.perf_counter()
        total_time = end_time - start_time
        
        # Render results
        self.Canvas.setMBRs(mbrs_res)
        
        # Display statistics to the user
        if valid_count > 0:
            avg_orig_p = orig_perim_total / valid_count
            avg_gen_p = gen_perim_total / valid_count
            reduction = (1 - (avg_gen_p / avg_orig_p)) * 100 if avg_orig_p > 0 else 0
            
            msg = f"<b>Metoda:</b> {algorithm_name}<br><br>"
            msg += f"<b>Zpracováno budov:</b> {valid_count}<br>"
            msg += f"<b>Celkový čas výpočtu:</b> {total_time:.4f} s<br><br>"
            msg += f"<b>Průměrný obvod (Původní):</b> {avg_orig_p:.2f} jednotek<br>"
            msg += f"<b>Průměrný obvod (LOD0):</b> {avg_gen_p:.2f} jednotek<br>"
            msg += f"<b>Vyhlazení (zmenšení obvodu):</b> {reduction:.1f} %"
            
            QtWidgets.QMessageBox.information(self.centralwidget, "Statistika generalizace", msg)


