    # =========================================================
    # CUSTOM METHODS AND LOGIC
    # =========================================================

    def loadShapefile(self, path):
        """Loads vector geospatial data using GeoPandas and converts it to QPolygons."""
        try:
            gdf = gpd.read_file(path)
            buildings_list = []
            
            for geom in gdf.geometry:
                if geom.geom_type == 'Polygon':
                    qpoly = QPolygonF()
                    for x, y in geom.exterior.coords:
                        qpoly.append(QPointF(x, y))
                    buildings_list.append(qpoly)
                    
                elif geom.geom_type == 'MultiPolygon':
                    for part in geom.geoms:
                        qpoly = QPolygonF()
                        for x, y in part.exterior.coords:
                            qpoly.append(QPointF(x, y))
                        buildings_list.append(qpoly)
            
            self.Canvas.setBuildings(buildings_list)
            
        except Exception as e:
            QtWidgets.QMessageBox.critical(
                self.centralwidget, "Error", f"Failed to load file:\n{e}"
            )
            
    def openShapefileClick(self):
        """Triggers the OS native file explorer to select a shapefile."""
        path, _ = QtWidgets.QFileDialog.getOpenFileName(
            self.centralwidget, "Open Shapefile", "", "ESRI Shapefiles (*.shp);;All Files (*)"
        )
        if path:
            self.loadShapefile(path)

    def clearAllClick(self):
        """Flushes the primary building list and all processing results from the canvas."""
        self.Canvas.clearAll()
            
    def clearResultsClick(self):
        """Flushes only the generalized rectangles, keeping original raw buildings loaded."""
        self.Canvas.clearResult()
        
